def signal_generator(df):
    if df is None or len(df) < 2:
        return ''

    signals = []

    # Retrieve depth data
    try:
        depth_data = client.depth(symbol=symbol)
        bid_depth = depth_data['bids']
        ask_depth = depth_data['asks']
    except:
        print("data ERROR")

    buy_price = float(bid_depth[0][0]) if bid_depth else 0.0
    sell_price = float(ask_depth[0][0]) if ask_depth else 0.0

    buy_qty = sum(float(bid[0]) * float(bid[1]) for bid in bid_depth)
    sell_qty = sum(float(ask[0]) * float(ask[1]) for ask in ask_depth)

    if buy_qty > sell_qty:
        signals.append('bullish')
    elif sell_qty > buy_qty:
        signals.append('bearish')

    try:
        mark_price_data = client.ticker_price(symbol=symbol)
        mark_price = float(mark_price_data['price']) if 'price' in mark_price_data else 0.0
    except:
        print("data ERROR")

    if 'bullish' in signals and buy_price < mark_price:
        return 'buy'
    elif 'bearish' in signals and sell_price > mark_price:
        return 'sell'
    else:
        return ''
```

In this updated code, the `buy_qty` is calculated as the sum of each bid's price (`bid[0]`) multiplied by its quantity (`bid[1]`). Similarly, the `sell_qty` is calculated as the sum of each ask's price (`ask[0]`) multiplied by its quantity (`ask[1]`).

With these corrections, the code now calculates the quantities correctly, allowing for proper generation of both buy and sell signals based on the provided strategy.
